import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithAllowMissingColumnNames_DefaultFalse() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertFalse(format.getAllowMissingColumnNames(), "Default CSVFormat should not allow missing column names");
    }

    @Test
    void testWithAllowMissingColumnNames_True() {
        CSVFormat format = CSVFormat.DEFAULT.withAllowMissingColumnNames();
        assertTrue(format.getAllowMissingColumnNames(), "CSVFormat withAllowMissingColumnNames() should allow missing column names");
    }

    @Test
    void testWithAllowMissingColumnNames_False() {
        CSVFormat format = CSVFormat.DEFAULT.withAllowMissingColumnNames(false);
        assertFalse(format.getAllowMissingColumnNames(), "CSVFormat withAllowMissingColumnNames(false) should not allow missing column names");
    }

    @Test
    void testWithAllowMissingColumnNames_ThenFalse() {
        CSVFormat format = CSVFormat.DEFAULT.withAllowMissingColumnNames().withAllowMissingColumnNames(false);
        assertFalse(format.getAllowMissingColumnNames(), "CSVFormat withAllowMissingColumnNames() then withAllowMissingColumnNames(false) should not allow missing column names");
    }

    @Test
    void testWithAllowMissingColumnNames_ThenTrue() {
        CSVFormat format = CSVFormat.DEFAULT.withAllowMissingColumnNames(false).withAllowMissingColumnNames();
        assertTrue(format.getAllowMissingColumnNames(), "CSVFormat withAllowMissingColumnNames(false) then withAllowMissingColumnNames() should allow missing column names");
    }
}
